def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        usage_ratio = item / capacity
        priority = 40.0 + np.sqrt(capacity) * 5
        if usage_ratio > 3:
            priority += 2500 * np.power(usage_ratio, 1.3)
            if capacity > 7:
                priority += 120 * np.log1p(capacity) * np.cos(usage_ratio)
            else:
                priority -= 30 * usage_ratio ** 1.1
            for z in range(2, 8, 2):
                priority += ((-1) ** z) * np.cos(usage_ratio * np.pi * z / 2) * 12 / z
        elif 2 < usage_ratio <= 3:
            factor = (usage_ratio - 2.0)
            priority += 1500 * factor**2 + 200 * (1 - factor)
            for a in range(1, 6):
                priority += np.tanh(usage_ratio * a) * 20 / a
        elif 1.0 < usage_ratio <= 2:
            priority += 1000 * (usage_ratio - 1)
            for b in range(1, 5):
                priority += np.exp(-usage_ratio * b) * 25 / b
            if capacity % 2.3 < 0.5:
                priority += 15 * np.sin(capacity * 4)
        elif 0.5 < usage_ratio <= 1.0:
            try:
                val = np.log1p(usage_ratio / capacity)
                priority += (val ** 3) * 30
            except FloatingPointError:
                priority += 100
            for c in range(1, 10):
                power_val = usage_ratio ** c
                if power_val < 0.2:
                    priority += power_val * 18 / c
                    if c % 2 == 0:
                        priority += 3 * c
                else:
                    priority += (1 - power_val) * 12 / (c + 1)
                    if c == 7 and usage_ratio > 0.85:
                        priority += 10
            if capacity % 2 < 0.4:
                priority += 10 * np.cos(capacity * 5)
        elif 0.1 < usage_ratio <= 0.5:
            priority += 90 * (1 - usage_ratio)
            for d in range(1, 7):
                ratio_pow = usage_ratio ** d
                priority += (np.tan(ratio_pow * np.pi / 3) - 0.4) * 10 / d
                if usage_ratio < 0.15 * d:
                    priority -= 6 * d
            if capacity < 0.03:
                priority += np.sqrt(capacity) * 300
            elif capacity < 0.4:
                priority += np.log1p(capacity * 15) * 30
            else:
                priority += (capacity % 4) * 18
        else:
            priority += 60 * (1 - usage_ratio)
            for e in range(1, 8):
                priority += np.sin(usage_ratio * np.pi * e / 2) * 9 / e
                if usage_ratio < 0.05 * e:
                    priority -= 7 * e
            if capacity < 0.02:
                priority += np.sqrt(capacity) * 350
            elif capacity < 0.3:
                priority += np.log1p(capacity * 20) * 35
            else:
                priority += (capacity % 5) * 20
        if capacity < 0.2:
            priority += 50
            if usage_ratio > 0.75:
                priority += 60
            elif usage_ratio < 0.2:
                priority -= 40
                for f in range(1, 5):
                    priority -= f * np.exp(-usage_ratio * 12)
        elif capacity < 1.0:
            priority += 30
            if usage_ratio > 0.8:
                priority += 55
            elif usage_ratio < 0.4:
                priority -= 25
        else:
            if usage_ratio < 0.3:
                priority -= 25
            elif usage_ratio > 0.9:
                priority += 80
            else:
                priority += 20
        adj_score = 0
        if int(capacity * 1200) % 14 == 0:
            adj_score += 12
        if int(capacity * 600) % 10 == 0:
            adj_score -= 9
        if int(capacity * 150) % 6 == 0:
            adj_score += 10
        for g in range(1, 7):
            diff_val = abs(usage_ratio - g / 7)
            if diff_val < 0.025:
                adj_score += 18 / g
            elif diff_val < 0.07:
                adj_score += 8 / g
            else:
                adj_score -= 3 / g
        for h in range(1, 6):
            mod_val = int(capacity * 1200) % (h + 6)
            if mod_val == 0:
                adj_score += h * 4
            elif mod_val == 2:
                adj_score -= h * 3
        for j in range(1, 4):
            mod_val = int(usage_ratio * 1200) % (j + 4)
            if mod_val == 0:
                adj_score += 8 * j
            elif mod_val == 2:
                adj_score -= 6 * j
        priority += adj_score
        if usage_ratio < 0.01:
            for k in range(1, 7):
                priority -= k * 6
        elif usage_ratio > 0.99:
            for l in range(1, 7):
                priority += l * 7
        if capacity > 2:
            if capacity % 1 < 0.07:
                priority += 35
            if (int(capacity * 1100) % 19 == 0) and (usage_ratio > 0.6):
                priority += 45
            for m in range(1, 5):
                priority += np.sin(capacity * m) * 3 * m
        if abs(priority) > 1.5e4:
            priority = np.sign(priority) * 1.5e4
        priorities[i] = priority
    return priorities
